create extension if not exists "pgcrypto";

create table if not exists public.users (
  id bigint generated by default as identity primary key,
  email text not null unique,
  username text not null unique,
  password_hash text not null,
  name text not null,
  gender text,
  created_at timestamptz default timezone('utc', now())
);

create table if not exists public.profiles (
  user_id bigint primary key references public.users(id) on delete cascade,
  age integer,
  height_cm numeric(6,2),
  weight_kg numeric(6,2),
  bmi numeric(5,2),
  goal text,
  target_weight numeric(6,2),
  preference text,
  allergies text,
  avatar_url text,
  updated_at timestamptz default timezone('utc', now())
);

create index if not exists idx_users_email on public.users (email);
create index if not exists idx_users_username on public.users (username);

-- Shared lookup tables
create table if not exists public.plan_levels (
  id serial primary key,
  code text unique not null check (code in ('Beginner', 'Intermediate', 'Advanced')),
  portion_multiplier numeric(4,2) not null,
  training_multiplier numeric(4,2) not null,
  notes text
);

insert into public.plan_levels (code, portion_multiplier, training_multiplier, notes)
values
  ('Beginner', 1.00, 1.00, 'Days 1-30'),
  ('Intermediate', 1.10, 1.15, 'Days 31-60 (+10% portions, +15% burn)'),
  ('Advanced', 1.20, 1.30, 'Days 61-90 (+20% portions, +30% burn)')
on conflict (code) do update
set portion_multiplier = excluded.portion_multiplier,
    training_multiplier = excluded.training_multiplier,
    notes = excluded.notes;

create table if not exists public.effort_adjustments (
  id serial primary key,
  code text unique not null check (code in ('high', 'low')),
  description text not null,
  kcal_delta integer not null,
  snack_delta integer not null
);

insert into public.effort_adjustments (code, description, kcal_delta, snack_delta)
values
  ('high', 'Add +150 kcal snack (banana + whey shake)', 150, 1),
  ('low', 'Remove one snack (-100 kcal)', -100, -1)
on conflict (code) do update
set description = excluded.description,
    kcal_delta = excluded.kcal_delta,
    snack_delta = excluded.snack_delta;

-- Meal planning tables
create table if not exists public.meal_goals (
  id uuid primary key default gen_random_uuid(),
  slug text unique not null,
  title text not null,
  kcal_target_min integer,
  kcal_target_max integer,
  protein_target_min integer,
  protein_target_max integer,
  carb_target_min integer,
  carb_target_max integer,
  fat_target_min integer,
  fat_target_max integer,
  notes text
);

create table if not exists public.meal_template_days (
  id uuid primary key default gen_random_uuid(),
  goal_id uuid references public.meal_goals(id) on delete cascade,
  level_id integer references public.plan_levels(id),
  weekday smallint not null check (weekday between 1 and 7),
  base_daily_kcal integer not null,
  base_daily_protein integer,
  base_daily_carbs integer,
  base_daily_fat integer,
  unique (goal_id, level_id, weekday)
);

create table if not exists public.meal_template_meals (
  id uuid primary key default gen_random_uuid(),
  template_day_id uuid references public.meal_template_days(id) on delete cascade,
  meal_label text not null,
  food_description text not null,
  base_kcal integer not null,
  base_protein integer,
  base_carbs integer,
  base_fat integer,
  meal_order smallint not null default 1
);

create table if not exists public.user_meal_plans (
  id uuid primary key default gen_random_uuid(),
  user_id bigint references public.users(id) on delete cascade,
  goal_id uuid references public.meal_goals(id),
  current_level_id integer references public.plan_levels(id),
  start_date date not null default current_date,
  current_day_index smallint not null default 1,
  active boolean not null default true,
  last_effort_adjustment_id integer references public.effort_adjustments(id),
  notes text
);

create table if not exists public.user_meal_logs (
  id uuid primary key default gen_random_uuid(),
  user_plan_id uuid references public.user_meal_plans(id) on delete cascade,
  log_date date not null,
  template_day_id uuid references public.meal_template_days(id),
  effort_adjustment_id integer references public.effort_adjustments(id),
  actual_kcal integer,
  actual_protein integer,
  actual_carbs integer,
  actual_fat integer,
  comments text,
  unique (user_plan_id, log_date)
);

-- Workout planning tables
create table if not exists public.workout_goals (
  id uuid primary key default gen_random_uuid(),
  slug text unique not null,
  title text not null,
  target_burn_min integer,
  target_burn_max integer,
  notes text
);

create table if not exists public.workout_template_days (
  id uuid primary key default gen_random_uuid(),
  goal_id uuid references public.workout_goals(id) on delete cascade,
  level_id integer references public.plan_levels(id),
  weekday smallint not null check (weekday between 1 and 7),
  base_burn integer not null,
  session_notes text,
  unique (goal_id, level_id, weekday)
);

create table if not exists public.workout_template_exercises (
  id uuid primary key default gen_random_uuid(),
  template_day_id uuid references public.workout_template_days(id) on delete cascade,
  exercise_name text not null,
  prescription text not null,
  reference_url text,
  sequence smallint not null default 1
);

create table if not exists public.user_workout_plans (
  id uuid primary key default gen_random_uuid(),
  user_id bigint references public.users(id) on delete cascade,
  goal_id uuid references public.workout_goals(id),
  current_level_id integer references public.plan_levels(id),
  start_date date not null default current_date,
  current_day_index smallint not null default 1,
  active boolean not null default true,
  last_effort_adjustment_id integer references public.effort_adjustments(id),
  notes text
);

create table if not exists public.user_workout_logs (
  id uuid primary key default gen_random_uuid(),
  user_plan_id uuid references public.user_workout_plans(id) on delete cascade,
  log_date date not null,
  template_day_id uuid references public.workout_template_days(id),
  effort_adjustment_id integer references public.effort_adjustments(id),
  perceived_intensity text,
  calories_burned integer,
  comments text,
  unique (user_plan_id, log_date)
);

create unique index if not exists idx_user_meal_plans_active
  on public.user_meal_plans (user_id)
  where active;

create unique index if not exists idx_user_workout_plans_active
  on public.user_workout_plans (user_id)
  where active;
select count(*) from users;

alter table if exists public.users
  drop constraint if exists users_email_key;

create table if not exists public.user_providers (
  id uuid primary key default gen_random_uuid(),
  user_id bigint not null references public.users(id) on delete cascade,
  provider text not null,
  provider_user_id text not null,
  created_at timestamptz default timezone('utc', now()),
  unique (provider, provider_user_id)
);

create index if not exists idx_user_providers_user_id
  on public.user_providers (user_id);
alter table if exists public.users
  drop constraint if exists users_email_key;

create table if not exists public.user_providers (
  id uuid primary key default gen_random_uuid(),
  user_id bigint not null references public.users(id) on delete cascade,
  provider text not null,
  provider_user_id text not null,
  created_at timestamptz default timezone('utc', now()),
  unique (provider, provider_user_id)
);

create index if not exists idx_user_providers_user_id
  on public.user_providers (user_id);
select provider, provider_user_id from public.user_providers limit 5;
drop table if exists public.user_workout_sessions cascade;
drop table if exists public.user_workout_plans cascade;
drop table if exists public.user_workout_streaks cascade;
drop table if exists public.workout_template_exercises cascade;
drop table if exists public.workout_template_days cascade;
drop table if exists public.workout_goals cascade;


create table if not exists public.workout_plan_configs (
  schema_version text primary key,
  config jsonb not null,
  created_at timestamptz default timezone('utc', now()),
  updated_at timestamptz default timezone('utc', now())
);

create table if not exists public.plan_levels (
  id serial primary key,
  code text unique not null check (code in ('Beginner', 'Intermediate', 'Advanced')),
  portion_multiplier numeric(4,2) not null,
  training_multiplier numeric(4,2) not null,
  notes text
);

insert into public.plan_levels (code, portion_multiplier, training_multiplier, notes)
values
  ('Beginner', 1.00, 1.00, 'Days 1-30'),
  ('Intermediate', 1.10, 1.15, 'Days 31-60 (+10% portions, +15% burn)'),
  ('Advanced', 1.20, 1.30, 'Days 61-90 (+20% portions, +30% burn)')
on conflict (code) do update
set portion_multiplier = excluded.portion_multiplier,
    training_multiplier = excluded.training_multiplier,
    notes = excluded.notes;

