-- Water intake tracking table
create table if not exists public.water_intake (
  id uuid primary key default gen_random_uuid(),
  user_id bigint not null references public.users(id) on delete cascade,
  date date not null,
  amount integer not null default 0 check (amount >= 0),
  updated_at timestamptz default timezone('utc', now()),
  unique (user_id, date)
);

create index if not exists idx_water_intake_user_id on public.water_intake (user_id);
create index if not exists idx_water_intake_date on public.water_intake (date);

-- Body measurements tracking table
create table if not exists public.body_measurements (
  id uuid primary key default gen_random_uuid(),
  user_id bigint not null references public.users(id) on delete cascade,
  measurement_date date not null,
  chest_cm numeric(6,2),
  arms_cm numeric(6,2),
  waist_cm numeric(6,2),
  hips_cm numeric(6,2),
  thighs_cm numeric(6,2),
  neck_cm numeric(6,2),
  created_at timestamptz default timezone('utc', now()),
  updated_at timestamptz default timezone('utc', now()),
  unique (user_id, measurement_date)
);

create index if not exists idx_body_measurements_user_id on public.body_measurements (user_id);
create index if not exists idx_body_measurements_date on public.body_measurements (measurement_date);

-- Strength records (Personal Records) tracking table
create table if not exists public.strength_records (
  id uuid primary key default gen_random_uuid(),
  user_id bigint not null references public.users(id) on delete cascade,
  exercise_name text not null,
  weight_kg numeric(6,2) not null,
  reps integer,
  sets integer,
  record_date date not null,
  notes text,
  created_at timestamptz default timezone('utc', now()),
  updated_at timestamptz default timezone('utc', now()),
  unique (user_id, exercise_name, record_date)
);

create index if not exists idx_strength_records_user_id on public.strength_records (user_id);
create index if not exists idx_strength_records_exercise on public.strength_records (exercise_name);
create index if not exists idx_strength_records_date on public.strength_records (record_date);

-- Progress photos tracking table
create table if not exists public.progress_photos (
  id uuid primary key default gen_random_uuid(),
  user_id bigint not null references public.users(id) on delete cascade,
  photo_date date not null,
  photo_url text not null,
  photo_type text check (photo_type in ('front', 'side', 'back', 'full')),
  notes text,
  created_at timestamptz default timezone('utc', now())
);

create index if not exists idx_progress_photos_user_id on public.progress_photos (user_id);
create index if not exists idx_progress_photos_date on public.progress_photos (photo_date);

-- Habit tracking table
create table if not exists public.habit_logs (
  id uuid primary key default gen_random_uuid(),
  user_id bigint not null references public.users(id) on delete cascade,
  date date not null,
  habit_type text not null check (habit_type in ('workout', 'meal', 'water', 'sleep', 'meditation', 'custom')),
  status text not null check (status in ('hit', 'partial', 'missed')),
  notes text,
  created_at timestamptz default timezone('utc', now()),
  updated_at timestamptz default timezone('utc', now()),
  unique (user_id, date, habit_type)
);

create index if not exists idx_habit_logs_user_id on public.habit_logs (user_id);
create index if not exists idx_habit_logs_date on public.habit_logs (date);
create index if not exists idx_habit_logs_type on public.habit_logs (habit_type);
ALTER TABLE public.body_measurements
ADD COLUMN IF NOT EXISTS weight_kg numeric(6,2),
ADD COLUMN IF NOT EXISTS notes text;

