create extension if not exists "pgcrypto";

-- Core meal tables
create table if not exists public.meal_goals (
  id uuid primary key default gen_random_uuid(),
  slug text unique not null,
  title text not null,
  kcal_target_min integer,
  kcal_target_max integer,
  protein_target_min integer,
  protein_target_max integer,
  carb_target_min integer,
  carb_target_max integer,
  fat_target_min integer,
  fat_target_max integer,
  notes text
);

create table if not exists public.meal_template_days (
  id uuid primary key default gen_random_uuid(),
  goal_id uuid references public.meal_goals(id) on delete cascade,
  level_id integer references public.plan_levels(id),
  weekday smallint not null check (weekday between 1 and 7),
  base_daily_kcal integer not null,
  base_daily_protein integer,
  base_daily_carbs integer,
  base_daily_fat integer,
  unique (goal_id, level_id, weekday)
);

create table if not exists public.meal_template_meals (
  id uuid primary key default gen_random_uuid(),
  template_day_id uuid references public.meal_template_days(id) on delete cascade,
  meal_label text not null,
  food_description text not null,
  base_kcal integer not null,
  base_protein integer,
  base_carbs integer,
  base_fat integer,
  meal_order smallint not null default 1
);

create table if not exists public.meal_template_options (
  id uuid primary key default gen_random_uuid(),
  template_meal_id uuid references public.meal_template_meals(id) on delete cascade,
  option_label text,
  food_description text not null,
  base_kcal integer not null,
  base_protein integer,
  base_carbs integer,
  base_fat integer,
  option_order smallint not null default 1
);

create index if not exists idx_meal_template_options_meal
  on public.meal_template_options (template_meal_id);

-- Seed goals
insert into public.meal_goals (
  slug, title,
  kcal_target_min, kcal_target_max,
  protein_target_min, protein_target_max,
  carb_target_min, carb_target_max,
  fat_target_min, fat_target_max,
  notes
) values
  ('lose-weight', 'Lose Weight', 1600, 1900, 120, 150, 150, 200, 40, 60, 'Higher protein, moderate carbs'),
  ('build-muscle', 'Build Muscle', 2200, 2600, 160, 200, 230, 290, 60, 80, 'Surplus with high protein'),
  ('improve-endurance', 'Improve Endurance', 2000, 2400, 130, 160, 260, 320, 50, 70, 'Higher carbs for fuel'),
  ('general-fitness', 'General Fitness', 1900, 2200, 120, 150, 200, 250, 55, 70, 'Balanced intake')
on conflict (slug) do update set
  title = excluded.title,
  kcal_target_min = excluded.kcal_target_min,
  kcal_target_max = excluded.kcal_target_max,
  protein_target_min = excluded.protein_target_min,
  protein_target_max = excluded.protein_target_max,
  carb_target_min = excluded.carb_target_min,
  carb_target_max = excluded.carb_target_max,
  fat_target_min = excluded.fat_target_min,
  fat_target_max = excluded.fat_target_max,
  notes = excluded.notes;

-- 7-day templates per goal x level
with goal_targets as (
  select
    id, slug,
    case slug
      when 'lose-weight' then 1800
      when 'build-muscle' then 2400
      when 'improve-endurance' then 2200
      else 2000
    end as kcal,
    case slug
      when 'lose-weight' then 140
      when 'build-muscle' then 180
      when 'improve-endurance' then 140
      else 130
    end as protein,
    case slug
      when 'lose-weight' then 180
      when 'build-muscle' then 260
      when 'improve-endurance' then 300
      else 230
    end as carbs,
    case slug
      when 'lose-weight' then 50
      when 'build-muscle' then 70
      when 'improve-endurance' then 60
      else 65
    end as fat
  from public.meal_goals
),
days as (select generate_series(1,7) as weekday),
levels as (select id, portion_multiplier from public.plan_levels)
insert into public.meal_template_days (
  goal_id, level_id, weekday,
  base_daily_kcal, base_daily_protein, base_daily_carbs, base_daily_fat
)
select
  g.id, l.id, d.weekday,
  round(g.kcal * l.portion_multiplier),
  round(g.protein * l.portion_multiplier),
  round(g.carbs * l.portion_multiplier),
  round(g.fat * l.portion_multiplier)
from goal_targets g
cross join levels l
cross join days d
on conflict (goal_id, level_id, weekday) do update set
  base_daily_kcal = excluded.base_daily_kcal,
  base_daily_protein = excluded.base_daily_protein,
  base_daily_carbs = excluded.base_daily_carbs,
  base_daily_fat = excluded.base_daily_fat;

-- Meals per day
with day_targets as (
  select
    mtd.id,
    mtd.base_daily_kcal, mtd.base_daily_protein, mtd.base_daily_carbs, mtd.base_daily_fat
  from public.meal_template_days mtd
),
meal_shares as (
  select * from (values
    ('Breakfast', 0.25, 1),
    ('Lunch',     0.30, 2),
    ('Snack',     0.15, 3),
    ('Dinner',    0.30, 4)
  ) as t(label, share, sort_order)
)
insert into public.meal_template_meals (
  template_day_id, meal_label, food_description,
  base_kcal, base_protein, base_carbs, base_fat, meal_order
)
select
  d.id,
  m.label,
  case m.label
    when 'Breakfast' then 'Greek yogurt, oats, berries'
    when 'Lunch' then 'Grilled chicken, quinoa, veggies'
    when 'Snack' then 'Protein shake, banana'
    else 'Salmon, sweet potato, greens'
  end as food_description,
  round(d.base_daily_kcal * m.share),
  round(d.base_daily_protein * m.share),
  round(d.base_daily_carbs * m.share),
  round(d.base_daily_fat * m.share),
  m.sort_order
from day_targets d
cross join meal_shares m
where not exists (
  select 1 from public.meal_template_meals mtm
  where mtm.template_day_id = d.id and mtm.meal_label = m.label
);

-- Swap options with same macros
insert into public.meal_template_options (
  template_meal_id, option_label, food_description,
  base_kcal, base_protein, base_carbs, base_fat, option_order
)
select
  m.id,
  'Swap option',
  case m.meal_label
    when 'Breakfast' then 'Egg white omelet, whole-grain toast, fruit'
    when 'Lunch' then 'Turkey wrap, brown rice, salad'
    when 'Snack' then 'Cottage cheese, apple'
    else 'Lean beef, brown rice, mixed vegetables'
  end as food_description,
  m.base_kcal, m.base_protein, m.base_carbs, m.base_fat,
  2
from public.meal_template_meals m
where not exists (
  select 1 from public.meal_template_options o
  where o.template_meal_id = m.id
);

commit;

