create or replace view public.v_today_target with (security_invoker = true) as
with params as (
  select
    u.id as user_id,
    current_date as target_date,
    extract(isodow from current_date)::int as weekday,
    0.15::numeric as burn_to_kcal_multiplier
  from public.users u
)
select
  p.user_id,
  p.target_date,
  mg.title as meal_goal,
  md.base_daily_kcal,
  md.base_daily_protein,
  md.base_daily_carbs,
  md.base_daily_fat,
  coalesce(wt.adjusted_burn, wt.base_burn, 0) as workout_burn_kcal,
  coalesce(wm.minutes, 0) as workout_minutes,
  round(md.base_daily_kcal + coalesce(wt.adjusted_burn, wt.base_burn, 0) * p.burn_to_kcal_multiplier)::int as target_kcal,
  coalesce(round(pr.weight_kg * 0.035, 2), 2.0) as water_liters
from params p
left join lateral (
  select *
  from public.user_meal_plans
  where user_id = p.user_id and active = true
  order by start_date desc
  limit 1
) ump on true
left join lateral (
  select mtd.*
  from public.meal_template_days mtd
  where mtd.goal_id = ump.goal_id
    and mtd.level_id = ump.current_level_id
    and mtd.weekday = p.weekday
  limit 1
) md on true
left join public.meal_goals mg on mg.id = ump.goal_id
left join lateral (
  select *
  from public.user_workout_plans
  where user_id = p.user_id
    and coalesce(archived, false) = false
  order by start_date desc
  limit 1
) uwp on true
left join lateral (
  select uws.*
  from public.user_workout_sessions uws
  where uws.plan_id = uwp.id
    and uws.scheduled_date = p.target_date
  limit 1
) wt on true
left join lateral (
  select sum(
    case
      when (item->>'prescription') ~* E'([0-9]+)\\s*min'
      then (regexp_match(item->>'prescription', E'([0-9]+)\\s*min', 'i'))[1]::int
      else 0
    end
  )::int as minutes
  from jsonb_array_elements(coalesce(wt.workouts, '[]'::jsonb)) item
) wm on true
left join public.profiles pr on pr.user_id = p.user_id;

