create or replace view public.v_today_target with (security_invoker = true) as
with params as (
  select
    u.id as user_id,
    current_date as target_date,
    extract(isodow from current_date)::int as weekday,
    0.15::numeric as burn_to_kcal_multiplier
  from public.users u
),
goal_slug as (
  select
    p.user_id,
    regexp_replace(
      regexp_replace(lower(coalesce(pr.goal, '')), '[^a-z0-9]+', '-', 'g'),
      '(^-+|-+$)',
      '',
      'g'
    ) as slug
  from params p
  left join public.profiles pr on pr.user_id = p.user_id
)
select
  p.user_id,
  p.target_date,
  mg.title as meal_goal,
  md.base_daily_kcal,
  md.base_daily_protein,
  md.base_daily_carbs,
  md.base_daily_fat,
  coalesce(wb.workout_burn, 0) as workout_burn_kcal,
  coalesce(wm.minutes, 0) as workout_minutes,
  round(md.base_daily_kcal + coalesce(wb.workout_burn, 0) * p.burn_to_kcal_multiplier)::int as target_kcal,
  coalesce(round(pr.weight_kg * 0.035, 2), 2.0) as water_liters
from params p
left join public.profiles pr on pr.user_id = p.user_id
left join goal_slug gs on gs.user_id = p.user_id
left join lateral (
  select mg.*
  from public.meal_goals mg
  where mg.slug = nullif(gs.slug, '')
     or (pr.goal is not null and lower(mg.title) = lower(pr.goal))
     or mg.slug = 'general-fitness'
  order by
    (mg.slug = nullif(gs.slug, '')) desc,
    (pr.goal is not null and lower(mg.title) = lower(pr.goal)) desc,
    (mg.slug = 'general-fitness') desc
  limit 1
) mg on true
left join lateral (
  select *
  from public.user_meal_plans
  where user_id = p.user_id and active = true
  order by start_date desc
  limit 1
) ump on true
left join lateral (
  select pl.*
  from public.plan_levels pl
  order by (pl.id = ump.current_level_id) desc, (pl.code = 'Beginner') desc
  limit 1
) pl on true
left join lateral (
  select mtd.*
  from public.meal_template_days mtd
  where mtd.goal_id = mg.id
    and mtd.level_id = pl.id
    and mtd.weekday = p.weekday
  limit 1
) md on true
left join lateral (
  select
    sum(coalesce(uws.adjusted_burn, uws.base_burn, 0))::int as workout_burn
  from public.user_workout_sessions uws
  join public.user_workout_plans uwp on uwp.id = uws.plan_id
  where uwp.user_id = p.user_id
    and uws.scheduled_date = p.target_date
) wb on true
left join lateral (
  select sum(
    case
      when (item->>'prescription') ~* E'([0-9]+)\\s*min'
      then (regexp_match(item->>'prescription', E'([0-9]+)\\s*min', 'i'))[1]::int
      else 0
    end
  )::int as minutes
  from public.user_workout_sessions uws
  join public.user_workout_plans uwp on uwp.id = uws.plan_id
  join lateral jsonb_array_elements(coalesce(uws.workouts, '[]'::jsonb)) item on true
  where uwp.user_id = p.user_id
    and uws.scheduled_date = p.target_date
) wm on true;

