)
on conflict (schema_version) do update
set config = excluded.config,
    updated_at = timezone('utc', now());

begin;

update public.workout_plan_configs
set config = jsonb_set(
  config,
  '{plan}',
  (
    select jsonb_object_agg(goal_key, goal_updated)
    from jsonb_each(coalesce(config->'plan','{}'::jsonb)) as g(goal_key, goal_val)
    cross join lateral (
      select jsonb_set(
        goal_val,
        '{seedWeek}',
        (
          select jsonb_object_agg(level_key, level_updated)
          from jsonb_each(coalesce(goal_val->'seedWeek','{}'::jsonb)) as l(level_key, level_val)
          cross join lateral (
            select jsonb_object_agg(day_key, day_updated)
            from jsonb_each(coalesce(level_val,'{}'::jsonb)) as d(day_key, day_val)
            cross join lateral (
              select jsonb_set(
                day_val,
                '{workouts}',
                (
                  select jsonb_agg(
                    case
                      when workout ? 'thumbnail' then workout
                      when (workout->>'video') is null then workout
                      else jsonb_set(
                        workout,
                        '{thumbnail}',
                        to_jsonb(
                          case
                            when video_id is null then 'images/athlete-lift.jpg'
                            else 'https://i.ytimg.com/vi/' || video_id || '/hqdefault.jpg'
                          end
                        ),
                        true
                      )
                    end
                    order by workout_ord
                  )
                  from jsonb_array_elements(coalesce(day_val->'workouts','[]'::jsonb)) with ordinality as w(workout, workout_ord)
                  cross join lateral (
                    select coalesce(
                      substring(w.workout->>'video' from 'v=([^&]+)'),
                      substring(w.workout->>'video' from 'youtu\.be/([^?&/]+)'),
                      substring(w.workout->>'video' from 'youtube\.com/shorts/([^?&/]+)'),
                      substring(w.workout->>'video' from 'youtube(?:-nocookie)?\.com/embed/([^?&/]+)'),
                      substring(w.workout->>'video' from 'youtube\.com/v/([^?&/]+)')
                    ) as video_id
                  ) as vid
                ),
                true
              ) as day_updated
            )
          ) as level_updated
        ),
        true
      ) as goal_updated
    )
  ),
  true
)
where schema_version = '1.0';

commit;

begin;

-- Add thumbnails to exercise_videos_v1 categories
update public.workout_plan_configs
set config = jsonb_set(
  config,
  '{categories}',
  (
    select jsonb_agg(
      jsonb_set(
        category,
        '{workouts}',
        (
          select jsonb_agg(
            case
              when workout ? 'thumbnail' then workout
              when (workout->>'video') is null then workout
              else jsonb_set(
                workout,
                '{thumbnail}',
                to_jsonb(
                  case
                    when video_id is null then 'images/athlete-lift.jpg'
                    else 'https://i.ytimg.com/vi/' || video_id || '/hqdefault.jpg'
                  end
                ),
                true
              )
            end
            order by workout_ord
          )
          from jsonb_array_elements(coalesce(category->'workouts','[]'::jsonb)) with ordinality as w(workout, workout_ord)
          cross join lateral (
            select coalesce(
              substring(w.workout->>'video' from 'v=([^&]+)'),
              substring(w.workout->>'video' from 'youtu\.be/([^?&/]+)'),
              substring(w.workout->>'video' from 'youtube\.com/shorts/([^?&/]+)'),
              substring(w.workout->>'video' from 'youtube(?:-nocookie)?\.com/embed/([^?&/]+)'),
              substring(w.workout->>'video' from 'youtube\.com/v/([^?&/]+)')
            ) as video_id
          ) as vid
        ),
        true
      )
      order by category_ord
    )
    from jsonb_array_elements(coalesce(config->'categories','[]'::jsonb)) with ordinality as c(category, category_ord)
  ),
  true
)
where schema_version = 'exercise_videos_v1';

