          select jsonb_object_agg(level_key, level_updated)
          from jsonb_each(coalesce(goal_val->'seedWeek','{}'::jsonb)) as l(level_key, level_val)
          cross join lateral (
            select jsonb_object_agg(day_key, day_updated)
            from jsonb_each(coalesce(level_val,'{}'::jsonb)) as d(day_key, day_val)
            cross join lateral (
              select jsonb_set(
                day_val,
                '{workouts}',
