                      substring(w.workout->>'video' from 'youtube\.com/shorts/([^?&/]+)'),
                      substring(w.workout->>'video' from 'youtube(?:-nocookie)?\.com/embed/([^?&/]+)'),
                      substring(w.workout->>'video' from 'youtube\.com/v/([^?&/]+)')
                    ) as video_id
                  ) as vid
                ),
                true
