with belly_list as (
  select $$[
    {"exercise":"Forearm Plank","prescription":"4x60s","video":"https://www.youtube.com/watch?v=pSHjTRCQxIw","thumbnail":"https://i.ytimg.com/vi/pSHjTRCQxIw/hqdefault.jpg"},
    {"exercise":"Plank","prescription":"3x35s","video":"https://www.youtube.com/watch?v=dnERKMqkd3k","thumbnail":"https://i.ytimg.com/vi/dnERKMqkd3k/hqdefault.jpg"},
    {"exercise":"Hanging Leg Raises","prescription":"4x12","video":"https://www.youtube.com/watch?v=JB2oyawG9KI","thumbnail":"https://i.ytimg.com/vi/JB2oyawG9KI/hqdefault.jpg"},
    {"exercise":"Russian Twists","prescription":"4x30 (15/side)","video":"https://www.youtube.com/watch?v=wkD8rjkodUI","thumbnail":"https://i.ytimg.com/vi/wkD8rjkodUI/hqdefault.jpg"},
    {"exercise":"Bicycle Crunch","prescription":"4x20","video":"https://www.youtube.com/watch?v=9FGilxCbdz8","thumbnail":"https://i.ytimg.com/vi/9FGilxCbdz8/hqdefault.jpg"},
    {"exercise":"Flutter Kicks","prescription":"4x40s","video":"https://www.youtube.com/watch?v=KM46AG4YuNM","thumbnail":"https://i.ytimg.com/vi/KM46AG4YuNM/hqdefault.jpg"},
    {"exercise":"Toe Touch Crunches","prescription":"4x15","video":"https://www.youtube.com/watch?v=JB2oyawG9KI","thumbnail":"https://i.ytimg.com/vi/JB2oyawG9KI/hqdefault.jpg"},
    {"exercise":"Side Plank","prescription":"3x45s (each side)","video":"https://www.youtube.com/watch?v=UrAUan4fPYE","thumbnail":"https://i.ytimg.com/vi/UrAUan4fPYE/hqdefault.jpg"},
    {"exercise":"Reverse Crunch","prescription":"4x15","video":"https://www.youtube.com/watch?v=hyv14e2QDq0","thumbnail":"https://i.ytimg.com/vi/hyv14e2QDq0/hqdefault.jpg"},
    {"exercise":"V-Ups","prescription":"4x12","video":"https://www.youtube.com/watch?v=iP2fjvG0g3w","thumbnail":"https://i.ytimg.com/vi/iP2fjvG0g3w/hqdefault.jpg"},
    {"exercise":"Hollow Body Hold","prescription":"3x30s","video":"https://www.youtube.com/watch?v=4xRpGgttca8","thumbnail":"https://i.ytimg.com/vi/4xRpGgttca8/hqdefault.jpg"},
    {"exercise":"Sit-Up","prescription":"3x20","video":"https://www.youtube.com/watch?v=1hwfvjSqhuc","thumbnail":"https://i.ytimg.com/vi/1hwfvjSqhuc/hqdefault.jpg"},
    {"exercise":"Dead Bug","prescription":"3x12 (each side)","video":"https://www.youtube.com/watch?v=jOwcnFip7jE","thumbnail":"https://i.ytimg.com/vi/jOwcnFip7jE/hqdefault.jpg"},
    {"exercise":"Leg Raises","prescription":"3x12","video":"https://www.youtube.com/watch?v=JB2oyawG9KI","thumbnail":"https://i.ytimg.com/vi/JB2oyawG9KI/hqdefault.jpg"}
  ]$$::jsonb as workouts
),
cardio_list as (
  select $$[
    {"exercise":"Jumping Jacks","prescription":"4x35s","video":"https://www.youtube.com/watch?v=RO_iZNEB9IU","thumbnail":"https://i.ytimg.com/vi/RO_iZNEB9IU/hqdefault.jpg"},
    {"exercise":"High Knees","prescription":"4x35s","video":"https://www.youtube.com/watch?v=y5nNMQSGbBQ","thumbnail":"https://i.ytimg.com/vi/y5nNMQSGbBQ/hqdefault.jpg"},
    {"exercise":"Burpees","prescription":"3x10","video":"https://www.youtube.com/watch?v=EmXaVk2k0GM","thumbnail":"https://i.ytimg.com/vi/EmXaVk2k0GM/hqdefault.jpg"},
    {"exercise":"Mountain Climbers","prescription":"4x30s","video":"https://www.youtube.com/watch?v=nmwgirgXLYM","thumbnail":"https://i.ytimg.com/vi/nmwgirgXLYM/hqdefault.jpg"}
  ]$$::jsonb as workouts
),
new_categories as (
  select w.schema_version,
         jsonb_agg(
           case
             when cat->>'category' = 'Belly' then jsonb_set(cat, '{workouts}', belly_list.workouts, true)
             when cat->>'category' = 'Cardio' then jsonb_set(cat, '{workouts}', cardio_list.workouts, true)
             else cat
           end
           order by ord
         ) as categories
  from public.workout_plan_configs w
  cross join belly_list
  cross join cardio_list
  cross join lateral jsonb_array_elements(w.config->'categories') with ordinality as t(cat, ord)
  where w.schema_version = 'exercise_videos_v1'
  group by w.schema_version
)
update public.workout_plan_configs w
set config = jsonb_set(w.config, '{categories}', new_categories.categories, true),
    updated_at = timezone('utc', now())
from new_categories
where w.schema_version = new_categories.schema_version;

select
  schema_version,
  jsonb_array_length(config->'categories') as category_count,
  jsonb_array_length(
    (select cat->'workouts'
     from jsonb_array_elements(config->'categories') cat
     where cat->>'category' = 'Belly'
     limit 1)
  ) as belly_count
from public.workout_plan_configs
where schema_version = 'exercise_videos_v1';
begin;

-- 1) Replace the exercise name inside the plan config (schema_version = '1.0')
update public.workout_plan_configs
set config = replace(config::text, '"Pull-ups / Assisted Rows"', '"Pull-ups"')::jsonb,
    updated_at = timezone('utc', now())
where schema_version = '1.0';

-- 2) Remove the duplicate from the exercise library (schema_version = 'exercise_videos_v1')
with updated as (
  select schema_version,
         coalesce(
           jsonb_agg(
             case
               when cat->>'category' = 'Back' then
                 jsonb_set(
                   cat,
                   '{workouts}',
                   coalesce(
                     (
                       select jsonb_agg(w)
                       from jsonb_array_elements(cat->'workouts') w
                       where w->>'exercise' <> 'Pull-ups / Assisted Rows'
                     ),
                     '[]'::jsonb
                   )
                 )
               else cat
             end
           ),
           '[]'::jsonb
         ) as categories
  from public.workout_plan_configs,
       jsonb_array_elements(config->'categories') as cat
  where schema_version = 'exercise_videos_v1'
  group by schema_version
)
update public.workout_plan_configs cfg
set config = jsonb_set(cfg.config, '{categories}', updated.categories, false),
    updated_at = timezone('utc', now())
from updated
where cfg.schema_version = updated.schema_version;

commit;

begin;

with updated as (
  select
    schema_version,
    jsonb_agg(
      case
        when cat->>'category' = 'Chest' then
          jsonb_set(
            cat,
            '{workouts}',
            (
              select jsonb_agg(
                case
                  when w->>'exercise' = 'Machine Chest Press' then
                    jsonb_set(
                      jsonb_set(w, '{video}', to_jsonb('https://www.youtube.com/watch?v=IvCU-PD5VpI'::text), false),
                      '{thumbnail}', to_jsonb('https://i.ytimg.com/vi/IvCU-PD5VpI/hqdefault.jpg'::text), false
                    )
                  when w->>'exercise' = 'Standard Push-Ups' then
                    jsonb_set(
                      jsonb_set(w, '{video}', to_jsonb('https://www.youtube.com/watch?v=mge3Q4nkMPI'::text), false),
                      '{thumbnail}', to_jsonb('https://i.ytimg.com/vi/mge3Q4nkMPI/hqdefault.jpg'::text), false
                    )
                  when w->>'exercise' = 'Decline Push-Ups' then
                    jsonb_set(
                      jsonb_set(w, '{video}', to_jsonb('https://www.youtube.com/watch?v=0V8xUxGvo4A'::text), false),
                      '{thumbnail}', to_jsonb('https://i.ytimg.com/vi/0V8xUxGvo4A/hqdefault.jpg'::text), false
                    )
                  when w->>'exercise' = 'Push-ups' then
                    jsonb_set(
                      jsonb_set(w, '{video}', to_jsonb('https://www.youtube.com/watch?v=xtEFVrwZFGU'::text), false),
                      '{thumbnail}', to_jsonb('https://i.ytimg.com/vi/xtEFVrwZFGU/hqdefault.jpg'::text), false
                    )
                  when w->>'exercise' = 'Wide Push-Up' then
                    jsonb_set(
                      jsonb_set(w, '{video}', to_jsonb('https://www.youtube.com/watch?v=XQyIOgypT00'::text), false),
                      '{thumbnail}', to_jsonb('https://i.ytimg.com/vi/XQyIOgypT00/hqdefault.jpg'::text), false
                    )
                  when w->>'exercise' = 'Elevated Push Up' then
                    jsonb_set(
                      jsonb_set(w, '{video}', to_jsonb('https://www.youtube.com/watch?v=qIDRj0LjIXA'::text), false),
                      '{thumbnail}', to_jsonb('https://i.ytimg.com/vi/qIDRj0LjIXA/hqdefault.jpg'::text), false
                    )
                  else w
                end
              )
              from jsonb_array_elements(cat->'workouts') w
            ),
            false
          )
        else cat
      end
    ) as categories
  from public.workout_plan_configs,
       jsonb_array_elements(config->'categories') as cat
  where schema_version = 'exercise_videos_v1'
  group by schema_version
)
update public.workout_plan_configs cfg
set config = jsonb_set(cfg.config, '{categories}', updated.categories, false),
    updated_at = timezone('utc', now())
from updated
where cfg.schema_version = updated.schema_version;

