create table if not exists public.user_week_anchors (
  user_id bigint primary key references public.users(id) on delete cascade,
  anchor_date date not null,
  created_at timestamptz default timezone('utc', now()),
  updated_at timestamptz default timezone('utc', now())
);

create table if not exists public.user_achievements (
  id uuid primary key default gen_random_uuid(),
  user_id bigint not null references public.users(id) on delete cascade,
  achievement_key text not null,
  title text,
  message text,
  created_at timestamptz default timezone('utc', now()),
  unique (user_id, achievement_key)
);

create index if not exists idx_user_achievements_user on public.user_achievements (user_id);
create index if not exists idx_user_achievements_created_at on public.user_achievements (created_at);
alter table public.users
  add column if not exists last_login_at timestamptz,
  add column if not exists inactivity_alert_sent_at timestamptz;

create table if not exists public.user_notification_preferences (
  user_id bigint primary key references public.users(id) on delete cascade,
  account_alerts_enabled boolean not null default true,
  updated_at timestamptz default timezone('utc', now())
);
